const initials=n=>String(n||'?').split(' ').filter(Boolean).slice(0,2).map(x=>x[0]).join('').toUpperCase();
const profilePhotoCache=new Map();
const encodedStoragePath=path=>String(path||'').split('/').map(encodeURIComponent).join('/');
async function storageFetch(path,opt={}){await ensureSession();let request=()=>fetch(API+path,{...opt,headers:{apikey:KEY,Authorization:'Bearer '+S.session.access_token,...(opt.headers||{})}}),response=await request();if(response.status===401){await refreshSession();response=await request()}return response}
async function privateProfilePhotoUrl(profile){const path=profile?.avatar_path;if(!path)return'';if(profilePhotoCache.has(path))return profilePhotoCache.get(path);const response=await storageFetch('/storage/v1/object/authenticated/profile-images/'+encodedStoragePath(path));if(!response.ok)throw Error('Não foi possível carregar a foto de perfil.');const url=URL.createObjectURL(await response.blob());profilePhotoCache.set(path,url);return url}
function releaseProfilePhoto(path){const url=profilePhotoCache.get(path);if(url)URL.revokeObjectURL(url);profilePhotoCache.delete(path)}
function releaseAllProfilePhotos(){for(const url of profilePhotoCache.values())URL.revokeObjectURL(url);profilePhotoCache.clear()}
const fmt=d=>d?new Date(d).toLocaleString('pt-BR',{dateStyle:'short',timeStyle:'short'}):'A definir';
const labels={pending:'Pendente',separating:'Em separação',scheduled:'Agendada',delivered:'Entregue',cancelled:'Cancelada'};
function toast(m){$('#toast').innerHTML=`<div class="toast">✓ ${esc(m)}</div>`;setTimeout(()=>$('#toast').innerHTML='',3200)}
async function json(r){let b=await r.json().catch(()=>({}));if(!r.ok)throw Error(b.message||b.msg||b.error_description||b.error||'Não foi possível concluir.');return b}
let sessionRefreshPromise=null;
async function refreshSession(){if(sessionRefreshPromise)return sessionRefreshPromise;sessionRefreshPromise=(async()=>{if(!S.session?.refresh_token)throw Error('Sua sessão terminou. Entre novamente.');let d=await json(await fetch(API+'/auth/v1/token?grant_type=refresh_token',{method:'POST',headers:{apikey:KEY,'Content-Type':'application/json'},body:JSON.stringify({refresh_token:S.session.refresh_token})}));d.expires_at=Math.floor(Date.now()/1000)+d.expires_in;localStorage.setItem('harmony.session',JSON.stringify(d));S.session=d;return d})().finally(()=>sessionRefreshPromise=null);return sessionRefreshPromise}
async function ensureSession(){if(!S.session?.access_token)throw Error('Sua sessão terminou. Entre novamente.');if(!S.session.expires_at||S.session.expires_at<Math.floor(Date.now()/1000)+90)await refreshSession()}
async function rest(path,opt={}){await ensureSession();let request=()=>fetch(API+'/rest/v1/'+path,{...opt,headers:{apikey:KEY,Authorization:'Bearer '+S.session.access_token,'Content-Type':'application/json',...(opt.headers||{})}}),r=await request();if(r.status===401){await refreshSession();r=await request()}return json(r)}
async function rpc(name,body){return rest('rpc/'+name,{method:'POST',body:JSON.stringify(body)})}
async function edge(body){await ensureSession();let request=()=>fetch(API+'/functions/v1/manage-user',{method:'POST',headers:{apikey:KEY,Authorization:'Bearer '+S.session.access_token,'Content-Type':'application/json'},body:JSON.stringify(body)}),r=await request();if(r.status===401){await refreshSession();r=await request()}return json(r)}
async function login(user,password){let d=await json(await fetch(API+'/auth/v1/token?grant_type=password',{method:'POST',headers:{apikey:KEY,'Content-Type':'application/json'},body:JSON.stringify({email:email(user),password})}));d.expires_at=Math.floor(Date.now()/1000)+d.expires_in;localStorage.setItem('harmony.session',JSON.stringify(d));S.session=d;await loadAccount()}
async function restore(){try{let d=JSON.parse(localStorage.getItem('harmony.session'));if(!d)return false;S.session=d;await ensureSession();await loadAccount();return true}catch{localStorage.removeItem('harmony.session');S.session=null;return false}}
async function loadAccount(){let p=await rest('profiles?id=eq.'+S.session.user.id+'&select=*');if(!p[0]||p[0].status!=='active')throw Error('Cadastro inativo.');S.profile=p[0];if(!S.profile.must_change_password)await loadData()}
async function loadData(){let [p,r,c,f]=await Promise.all([rest('products?select=*&order=name.asc'),rest('requests?select=*&order=created_at.desc'),rest('categories?select=*&order=name.asc'),rest('custom_field_definitions?select=*&order=scope.asc,position.asc')]);S.products=p;S.requests=r;S.categories=c;S.fields=f;S.paymentSchedules=[];if(S.profile.role==='admin'){[S.team,S.paymentSchedules]=await Promise.all([rest('profiles?select=*&order=full_name.asc'),rpc('list_production_payment_schedules',{})])}else if(S.profile.role==='receiver')S.team=await rpc('list_production_workers',{});else S.team=[S.profile]}
async function logout(){try{if(typeof cleanupPushSubscription==='function')await cleanupPushSubscription()}catch{}try{await ensureSession();await fetch(API+'/auth/v1/logout',{method:'POST',headers:{apikey:KEY,Authorization:'Bearer '+S.session.access_token}})}catch{}releaseAllProfilePhotos();localStorage.removeItem('harmony.session');S.session=S.profile=null;renderLogin()}
function renderLogin(){S.view='home';$('#app').innerHTML=`<main class="login"><section class="story"><p class="eyebrow">HARMONY STORE OFICIAL</p><h1>Cuidado artesanal,<br><em>gestão impecável.</em></h1><p>Materiais, solicitações e entregas reunidos em um ambiente seguro, criado para a rotina da nossa produção.</p><div class="artisan"><i>✦</i><span><b>Feito para a nossa essência</b><small>Organização leve, delicada e eficiente.</small></span></div></section><section class="login-panel"><div class="login-box"><img src="logo.jpg" alt="Harmony Store Oficial"><div class="login-copy"><p class="eyebrow">ACESSO RESTRITO</p><h2>Bem-vinda</h2><p>Use o login criado pela administradora.</p></div><form id="loginForm"><label>Login<input name="user" placeholder="seu.login" autocomplete="username" required></label><label>Senha<div class="password"><input name="password" type="password" autocomplete="current-password" required><button type="button" id="showPass">Ver</button></div></label><div id="loginError"></div><button class="primary">Entrar no sistema</button></form><small class="safe">Seus dados são protegidos. Nunca compartilhe sua senha.</small></div></section></main>`;$('#showPass').onclick=()=>{let i=$('[name=password]');i.type=i.type==='password'?'text':'password';$('#showPass').textContent=i.type==='password'?'Ver':'Ocultar'};$('#loginForm').onsubmit=async e=>{e.preventDefault();let b=e.submitter;b.disabled=true;try{await login(e.target.user.value,e.target.password.value);renderApp()}catch(x){$('#loginError').innerHTML=`<div class="error">${esc(/invalid login/i.test(x.message)?'Login ou senha incorretos.':x.message)}</div>`;b.disabled=false}}}
const nav=(v,i,t)=>`<button class="nav ${S.view===v?'active':''}" data-view="${v}"><i>${i}</i>${t}</button>`;
function passwordIssue(password){if(password.length<10)return'A senha deve ter pelo menos 10 caracteres.';if(password.length>72)return'A senha deve ter no máximo 72 caracteres.';if(!/[a-z]/.test(password)||!/[A-Z]/.test(password)||!/\d/.test(password)||!/[^A-Za-z0-9]/.test(password))return'Use letra maiúscula, letra minúscula, número e símbolo.';return''}
async function changeOwnPassword(password){await edge({action:'change-own-password',password});S.profile.must_change_password=false;await loadData()}
function renderRequiredPasswordChange(){document.documentElement.dataset.role=S.profile.role;$('#app').innerHTML=`<main class="password-gate"><section class="password-gate-card"><img src="brand-mark.png" alt="Harmony Store Oficial"><p class="eyebrow">PRIMEIRO ACESSO SEGURO</p><h1>Crie sua nova senha</h1><p>Olá, <b>${esc(S.profile.full_name.split(' ')[0])}</b>. A senha entregue pela administradora é temporária. Escolha uma senha pessoal para continuar.</p><form id="requiredPasswordForm"><label>Nova senha<div class="password"><input name="password" type="password" minlength="10" maxlength="72" autocomplete="new-password" required><button type="button" data-show-password="password">Ver</button></div></label><label>Confirmar nova senha<div class="password"><input name="confirm" type="password" minlength="10" maxlength="72" autocomplete="new-password" required><button type="button" data-show-password="confirm">Ver</button></div></label><div class="password-rules"><b>Sua senha precisa ter:</b><span>10 ou mais caracteres</span><span>Letra maiúscula e minúscula</span><span>Número e símbolo</span></div><div id="requiredPasswordError"></div><button class="primary full">Salvar nova senha e continuar</button></form><button class="outline password-gate-logout" id="passwordGateLogout">Sair e trocar de conta</button><small class="safe">A administradora não verá sua nova senha.</small></section></main>`;document.querySelectorAll('[data-show-password]').forEach(button=>button.onclick=()=>{let input=$(`#requiredPasswordForm [name="${button.dataset.showPassword}"]`);input.type=input.type==='password'?'text':'password';button.textContent=input.type==='password'?'Ver':'Ocultar'});$('#passwordGateLogout').onclick=logout;$('#requiredPasswordForm').onsubmit=async e=>{e.preventDefault();let button=e.submitter,password=e.target.password.value,confirm=e.target.confirm.value,error=passwordIssue(password);if(!error&&password!==confirm)error='As senhas não coincidem.';if(error){$('#requiredPasswordError').innerHTML=`<div class="error">${esc(error)}</div>`;return}button.disabled=true;try{await changeOwnPassword(password);renderApp();toast('Nova senha salva com segurança.')}catch(x){$('#requiredPasswordError').innerHTML=`<div class="error">${esc(x.message)}</div>`;button.disabled=false}}}
function renderApp(){if(S.profile?.must_change_password)return renderRequiredPasswordChange();let a=S.profile.role==='admin';$('#app').innerHTML=`<main class="shell"><aside class="sidebar"><button class="brand" data-view="home"><img src="logo.jpg" alt="Harmony Store"><span><b>Harmony Store</b><small>Gestão de produção</small></span></button><div class="account"><i class="avatar">${initials(S.profile.full_name)}</i><span><b>${esc(S.profile.full_name)}</b><small>${a?'Administradora':'Colaboradora'}</small></span></div><nav><small>PRINCIPAL</small>${nav('home','⌂','Visão geral')}${!a?nav('new','＋','Nova solicitação'):''}${nav('requests','▤',a?'Solicitações':'Meus pedidos')}${a?'<small>GESTÃO</small>'+nav('products','◇','Produtos e estoque')+nav('categories','▦','Categorias')+nav('team','♙','Colaboradoras')+nav('fields','⚙','Campos personalizados')+nav('audit','◷','Histórico'):''}<small>CONTA</small>${nav('profile','○','Meu perfil')}</nav><button class="outline logout" id="logout">Sair do sistema</button></aside><section class="content"><header class="topbar"><b>✦ Ambiente oficial Harmony</b><span>Dados protegidos e sincronizados</span></header><div id="page"></div></section></main>`;document.querySelectorAll('[data-view]').forEach(b=>b.onclick=()=>{S.view=b.dataset.view;renderApp()});$('#logout').onclick=logout;renderPage()}
const head=(e,t,s,a='')=>`<header class="page-head"><div><p class="eyebrow">${e}</p><h1>${t}</h1><span>${s}</span></div><div class="head-actions">${a}</div></header>`;
function requestRows(){if(!S.requests.length)return '<div class="empty">Nenhuma solicitação encontrada.</div>';return '<div class="requests">'+S.requests.map(r=>{let u=S.team.find(x=>x.id===r.requested_by);return `<article data-request="${r.id}"><div><small>SOLICITAÇÃO</small><b>#${String(r.protocol).padStart(4,'0')}</b></div><div><strong>${esc(r.notes||'Materiais para produção')}</strong><small>${fmt(r.created_at)}</small></div><div><small>SOLICITANTE</small><b>${esc(u?.full_name||S.profile.full_name)}</b></div><div><small>DATA PROGRAMADA</small><b>${fmt(r.scheduled_for)}</b></div><span class="badge ${r.status}">${labels[r.status]||r.status}</span></article>`}).join('')+'</div>'}
function bindRequests(){document.querySelectorAll('[data-request]').forEach(x=>x.onclick=()=>requestModalV2(S.requests.find(r=>r.id===x.dataset.request)))}
async function renderPage(){let p=$('#page'),a=S.profile.role==='admin';if(S.view==='home'){let low=S.products.filter(x=>+x.physical_stock-+x.reserved_stock<=+x.minimum_stock).length;p.innerHTML=`<div class="page">${head('VISÃO GERAL','Olá, '+esc(S.profile.full_name.split(' ')[0])+'.',a?'Aqui está o resumo da operação da Harmony Store.':'Acompanhe seus pedidos e solicite materiais.')}<div class="metrics"><article class="metric"><b>${S.requests.filter(r=>!['delivered','cancelled'].includes(r.status)).length}</b><p>Em andamento</p></article><article class="metric"><b>${S.requests.filter(r=>r.status==='pending').length}</b><p>Aguardando separação</p></article><article class="metric"><b>${S.requests.filter(r=>r.status==='delivered').length}</b><p>Entregas concluídas</p></article><article class="metric"><b>${a?low:S.products.length}</b><p>${a?'Estoque baixo':'Materiais disponíveis'}</p></article></div><section class="card"><div class="card-head"><h2>Solicitações recentes</h2></div>${requestRows()}</section></div>`;bindRequests()}
else if(S.view==='requests'){p.innerHTML=`<div class="page">${head('OPERAÇÃO',a?'Solicitações':'Meus pedidos',a?'Analise, separe, agende e conclua os pedidos.':'Somente suas solicitações aparecem aqui.')}<section class="card">${requestRows()}</section></div>`;bindRequests()}
else if(S.view==='new')renderNew(p);else if(S.view==='products')renderProducts(p);else if(S.view==='categories')renderCategories(p);else if(S.view==='team')renderTeam(p);else if(S.view==='fields')renderFields(p);else if(S.view==='audit')await renderAudit(p);else renderProfile(p)}
function renderNew(p){let productionProducts=S.products.filter(x=>x.usage_scope==='production'),selected=productionProducts.filter(x=>(S.cart[x.id]||0)>0);p.innerHTML=`<div class="page">${head('SOLICITAÇÃO','Escolha seus materiais','A empresa definirá a data e se será entrega ou coleta.')}<div class="catalog-layout"><section class="products-grid">${productionProducts.filter(x=>x.active).map(x=>`<article class="product">${x.image_path?`<img src="${API}/storage/v1/object/public/product-images/${esc(x.image_path)}" alt="${esc(x.name)}">`:`<i class="photo" style="background:${esc(x.color||'#f3b6d2')}">✦</i>`}<div><small>${esc(x.unit)}</small><h3>${esc(x.name)}</h3><p>${esc(x.description||x.color||'Material de produção')}</p><b>${+x.physical_stock-+x.reserved_stock} disponíveis</b></div><div class="qty"><button data-minus="${x.id}">−</button><input data-qty="${x.id}" type="number" min="0" step="0.001" value="${S.cart[x.id]||0}"><button data-plus="${x.id}">＋</button></div></article>`).join('')||'<div class="empty">Nenhum produto disponível.</div>'}</section><aside class="card summary"><p class="eyebrow">SEU PEDIDO</p><h2>${selected.length} produtos</h2>${selected.map(x=>`<div class="summary-line"><span>${esc(x.name)}</span><b>${S.cart[x.id]} ${esc(x.unit)}</b></div>`).join('')}<textarea id="reqNotes" placeholder="Finalidade, lote ou detalhe importante…"></textarea><button class="primary full" id="sendReq" ${selected.length?'':'disabled'}>Enviar solicitação</button></aside></div></div>`;document.querySelectorAll('[data-minus]').forEach(b=>b.onclick=()=>{S.cart[b.dataset.minus]=Math.max(0,(S.cart[b.dataset.minus]||0)-1);renderNew(p)});document.querySelectorAll('[data-plus]').forEach(b=>b.onclick=()=>{S.cart[b.dataset.plus]=(S.cart[b.dataset.plus]||0)+1;renderNew(p)});document.querySelectorAll('[data-qty]').forEach(i=>i.onchange=()=>{S.cart[i.dataset.qty]=Math.max(0,+i.value);renderNew(p)});$('#sendReq').onclick=async()=>{let b=$('#sendReq');b.disabled=true;try{let r=await rest('requests',{method:'POST',headers:{Prefer:'return=representation'},body:JSON.stringify({requested_by:S.profile.id,notes:$('#reqNotes').value,status:'pending'})});await rest('request_items',{method:'POST',body:JSON.stringify(selected.map(x=>({request_id:r[0].id,product_id:x.id,requested_quantity:S.cart[x.id]})))});S.cart={};await loadData();S.view='requests';renderApp();toast('Solicitação enviada com sucesso.')}catch(e){alert(e.message);b.disabled=false}}}
function renderProducts(p){p.innerHTML=`<div class="page">${head('GESTÃO','Produtos e estoque','Cadastre, edite e controle as matérias-primas.','<button class="primary" id="newProduct">＋ Cadastrar produto</button>')}<section class="card table-wrap"><div class="table"><header><span>Produto</span><span>Estoque físico</span><span>Reservado</span><span>Disponível</span><span>Situação</span><span>Ações</span></header>${S.products.map(x=>{let av=+x.physical_stock-+x.reserved_stock;return `<article><span class="table-product">${x.image_path?`<img src="${API}/storage/v1/object/public/product-images/${esc(x.image_path)}">`:`<i style="background:${esc(x.color||'#f3c5da')}"></i>`}<b>${esc(x.name)}<small>${esc(x.unit)}</small></b></span><span>${x.physical_stock}</span><span>${x.reserved_stock}</span><b>${av}</b><span class="badge ${av<=+x.minimum_stock?'low':'normal'}">${av<=+x.minimum_stock?'Estoque baixo':'Normal'}</span><span class="actions"><button class="ghost" data-edit-product="${x.id}">Editar</button><button class="danger" data-delete-product="${x.id}">Excluir</button></span></article>`}).join('')||'<div class="empty">Nenhum produto cadastrado.</div>'}</div></section></div>`;$('#newProduct').onclick=()=>productModal();document.querySelectorAll('[data-edit-product]').forEach(b=>b.onclick=()=>productModal(S.products.find(x=>x.id===b.dataset.editProduct)));document.querySelectorAll('[data-delete-product]').forEach(b=>b.onclick=async()=>{if(!confirm('Excluir este produto?'))return;try{const imagePath=await rpc('admin_delete_product',{p_product_id:b.dataset.deleteProduct});if(imagePath)storageFetch('/storage/v1/object/product-images/'+encodedStoragePath(imagePath),{method:'DELETE'}).catch(()=>{});await loadData();renderApp();toast('Produto excluído.')}catch(e){alert('Este produto pode estar vinculado a solicitações. '+e.message)}})}
async function customValues(scope,id){let defs=S.fields.filter(f=>f.scope===scope&&f.active),vals=id?await rest(`custom_field_values?${scope}_id=eq.${id}&select=*`):[];return {defs,vals}}
function customInputs(defs,vals){return defs.map(d=>{let v=vals.find(x=>x.definition_id===d.id)?.value??'',attr=`data-custom="${d.id}"`;if(d.field_type==='boolean')return `<label class="check"><input ${attr} type="checkbox" ${v===true?'checked':''}>${esc(d.label)}</label>`;if(d.field_type==='select')return `<label>${esc(d.label)}<select ${attr}>${d.options.map(o=>`<option ${v===o?'selected':''}>${esc(o)}</option>`).join('')}</select></label>`;return `<label class="${d.field_type==='textarea'?'wide':''}">${esc(d.label)}<${d.field_type==='textarea'?'textarea':'input'} ${attr} ${d.required?'required':''} type="${d.field_type==='number'?'number':d.field_type==='date'?'date':'text'}" value="${d.field_type==='textarea'?'':esc(v)}">${d.field_type==='textarea'?esc(v):''}</${d.field_type==='textarea'?'textarea':'input'}></label>`}).join('')}
async function saveCustom(scope,id){let rows=[...document.querySelectorAll('[data-custom]')].map(el=>({definition_id:el.dataset.custom,[scope+'_id']:id,value:el.type==='checkbox'?el.checked:el.type==='number'?+el.value:el.value}));if(rows.length)await rest('custom_field_values?on_conflict=definition_id,product_id,profile_id',{method:'POST',headers:{Prefer:'resolution=merge-duplicates'},body:JSON.stringify(rows)})}
async function productModal(x={}){
  const {defs,vals}=await customValues('product',x.id);
  let supply={suppliers:[],selectedSupplierId:'',available:false,error:''};
  try{
    const integration=window.HarmonyIntelligence;
    if(integration?.productSupplyContext)supply={...await integration.productSupplyContext(x.id),available:true,error:''};
    else supply.error='A integração de fornecedores ainda não foi carregada.';
  }catch(error){supply.error=error.message||'Não foi possível carregar os fornecedores.'}
  const supplierField=supply.available
    ?`<label>Fornecedor principal<select name="supplier_id"><option value="">Sem fornecedor principal</option>${supply.suppliers.map(item=>`<option value="${item.id}" ${item.id===supply.selectedSupplierId?'selected':''}>${esc(item.name)}</option>`).join('')}</select><small class="field-help">Cadastro compartilhado com Inteligência e Compras.</small></label>`
    :`<label>Fornecedor principal<select name="supplier_id" disabled><option>Indisponível no momento</option></select><small class="field-help">${esc(supply.error)} O produto ainda poderá ser salvo normalmente.</small></label>`;
  $('#modal').innerHTML=`<div class="modal"><form class="modal-box" id="productForm"><div class="modal-head"><div><p class="eyebrow">PRODUTO</p><h2>${x.id?'Editar produto':'Novo produto'}</h2></div><button type="button" data-close>×</button></div><div class="form"><label>Nome<input name="name" value="${esc(x.name||'')}" required></label><label>Categoria<select name="category_id"><option value="">Sem categoria</option>${S.categories.filter(c=>c.active).map(c=>`<option value="${c.id}" ${x.category_id===c.id?'selected':''}>${esc(c.name)}</option>`).join('')}</select></label>${supplierField}<label>Unidade<select name="unit">${['unidade','quilo','cm','metro','rolo','garrafa','caixa'].map(u=>`<option ${x.unit===u?'selected':''}>${u}</option>`).join('')}</select></label><label>Cor<input name="color" value="${esc(x.color||'')}"></label><label>Estoque físico<input name="physical_stock" type="number" min="0" step=".001" value="${x.physical_stock||0}" required></label><label>Reservado<input name="reserved_stock" type="number" min="0" step=".001" value="${x.reserved_stock||0}" required></label><label>Estoque mínimo<input name="minimum_stock" type="number" min="0" step=".001" value="${x.minimum_stock||0}" required></label><label>Foto<input name="photo" type="file" accept="image/jpeg,image/png,image/webp"></label><label class="check"><input name="active" type="checkbox" ${x.active!==false?'checked':''}>Produto ativo</label><label class="wide">Descrição<textarea name="description">${esc(x.description||'')}</textarea></label>${customInputs(defs,vals)}<div class="form-actions"><button type="button" class="outline" data-close>Cancelar</button><button class="primary">Salvar produto</button></div></div></form></div>`;
  document.querySelectorAll('[data-close]').forEach(b=>b.onclick=()=>$('#modal').innerHTML='');
  $('#productForm').onsubmit=async e=>{
    e.preventDefault();const button=e.submitter;button.disabled=true;
    const f=new FormData(e.target),data={name:f.get('name'),category_id:f.get('category_id')||null,unit:f.get('unit'),color:f.get('color')||null,description:f.get('description')||null,physical_stock:+f.get('physical_stock'),reserved_stock:+f.get('reserved_stock'),minimum_stock:+f.get('minimum_stock'),active:f.get('active')==='on'};
    if(data.reserved_stock>data.physical_stock){button.disabled=false;return alert('O reservado não pode ser maior que o estoque físico.')}
    let uploadedPath='';
    try{
      const file=f.get('photo');
      if(file?.size){if(file.size>2097152)throw Error('A foto deve ter no máximo 2 MB.');uploadedPath=S.profile.id+'/'+crypto.randomUUID()+'-'+file.name.replace(/[^a-zA-Z0-9._-]/g,'-');const upload=await storageFetch('/storage/v1/object/product-images/'+encodedStoragePath(uploadedPath),{method:'POST',headers:{'Content-Type':file.type},body:file});await json(upload);data.image_path=uploadedPath}
      const customValues=[...document.querySelectorAll('[data-custom]')].map(el=>({definition_id:el.dataset.custom,value:el.type==='checkbox'?el.checked:el.type==='number'?+el.value:el.value}));
      await rpc('admin_save_product',{p_product_id:x.id||null,p_product:data,p_supplier_id:supply.available?(f.get('supplier_id')||null):null,p_custom_values:customValues,p_manage_supplier:supply.available});
      if(uploadedPath&&x.image_path)storageFetch('/storage/v1/object/product-images/'+encodedStoragePath(x.image_path),{method:'DELETE'}).catch(()=>{});
      $('#modal').innerHTML='';await loadData();renderApp();toast(x.id?'Produto e fornecedor atualizados.':'Produto e fornecedor cadastrados.');
    }catch(err){
      if(uploadedPath)storageFetch('/storage/v1/object/product-images/'+encodedStoragePath(uploadedPath),{method:'DELETE'}).catch(()=>{});
      alert(err.message);button.disabled=false;
    }
  };
}

