function paymentScheduleFields(x){const schedule=paymentScheduleFor(x.id)||{},eligible=!x.id||['collaborator','receiver'].includes(x.role),active=Boolean(schedule.active);return `<fieldset class="profile-payment-schedule wide" ${eligible?'':'hidden'}><legend>Agenda individual de pagamento</legend><p>A produção recebida até o corte entrará no pagamento indicado. Cada colaboradora pode ter dias diferentes.</p><label class="check"><input name="payment_schedule_active" type="checkbox" ${active?'checked':''}>Ativar agenda de pagamento</label><div class="payment-schedule-fields"><label>Dia do corte<select name="cutoff_weekday">${weekdayOptions(schedule.cutoff_weekday||1)}</select></label><label>Horário do corte<input name="cutoff_time" type="time" value="${String(schedule.cutoff_time||'18:00').slice(0,5)}"></label><label>Dia do pagamento<select name="payment_weekday">${weekdayOptions(schedule.payment_weekday||3)}</select></label></div><small>Ao ativar, todos os recebimentos ainda abertos desta colaboradora serão organizados na próxima data válida.</small></fieldset>`}
async function userModal(x={}){let {defs,vals}=await customValues('profile',x.id);$('#modal').innerHTML=`<div class="modal"><form class="modal-box" id="userForm"><div class="modal-head"><div><p class="eyebrow">ACESSO</p><h2>${x.id?'Editar cadastro':'Nova colaboradora'}</h2></div><button type="button" data-close>×</button></div><div class="form"><label>Nome completo<input name="full_name" value="${esc(x.full_name||'')}" required></label><label>CPF<input name="cpf" inputmode="numeric" maxlength="14" placeholder="000.000.000-00"></label><label>Login<input name="username" value="${esc(x.username||'')}" required></label><label>Senha ${x.id?'(deixe vazio para manter)':''}<div class="password"><input name="password" type="password" ${x.id?'':'required'} minlength="10" maxlength="72"><button type="button" id="showUserPass">Ver</button></div><small class="field-help">Use maiúscula, minúscula, número e símbolo.</small></label><label>Perfil<select name="role" ${x.is_primary_admin?'disabled':''}><option value="collaborator" ${x.role==='collaborator'||!x.role?'selected':''}>Colaboradora</option><option value="receiver" ${x.role==='receiver'?'selected':''}>Colaboradora de recebimento</option><option value="admin" ${x.role==='admin'?'selected':''}>Administradora</option></select></label><label>Situação<select name="status" ${x.is_primary_admin?'disabled':''}><option value="active">Ativo</option><option value="inactive" ${x.status==='inactive'?'selected':''}>Inativo</option></select></label><label>Setor<input name="department" value="${esc(x.department||'')}"></label><label>Telefone<input name="phone" value="${esc(x.phone||'')}"></label>${paymentScheduleFields(x)}${customInputs(defs,vals)}<div class="form-actions"><button type="button" class="outline" data-close>Cancelar</button><button class="primary">Salvar cadastro</button></div></div></form></div>`;document.querySelectorAll('[data-close]').forEach(b=>b.onclick=()=>$('#modal').innerHTML='');$('#showUserPass').onclick=()=>{let i=$('#userForm [name=password]');i.type=i.type==='password'?'text':'password'};const roleSelect=$('#userForm [name=role]'),scheduleBox=$('#userForm .profile-payment-schedule');const toggleSchedule=()=>scheduleBox.hidden=roleSelect.value==='admin';roleSelect.onchange=toggleSchedule;toggleSchedule();$('#userForm').onsubmit=async e=>{e.preventDefault();let f=new FormData(e.target),body={action:x.id?'update':'create',id:x.id,full_name:f.get('full_name'),cpf:f.get('cpf'),username:f.get('username'),password:f.get('password'),role:f.get('role')||'admin',status:f.get('status')||'active',department:f.get('department'),phone:f.get('phone')};try{let result=await edge(body),id=x.id||result.id;await saveCustom('profile',id);if(body.role!=='admin')await rpc('admin_save_production_payment_schedule',{p_worker_id:id,p_payment_weekday:Number(f.get('payment_weekday')||3),p_cutoff_weekday:Number(f.get('cutoff_weekday')||1),p_cutoff_time:f.get('cutoff_time')||'18:00',p_active:f.get('payment_schedule_active')==='on'});$('#modal').innerHTML='';await loadData();renderApp();toast('Cadastro e agenda salvos com segurança.')}catch(err){alert(err.message)}}}

