let auditPage=0,auditSearch='',auditFrom='',auditTo='';
async function renderAudit(p){
  const pageSize=50,offset=auditPage*pageSize;
  S.audit=await rpc('admin_list_audit_logs',{p_limit:pageSize,p_offset:offset,p_search:auditSearch||null,p_from:auditFrom?new Date(auditFrom+'T00:00:00').toISOString():null,p_to:auditTo?new Date(auditTo+'T23:59:59.999').toISOString():null});
  const total=+(S.audit[0]?.total_count||0),pages=Math.max(1,Math.ceil(total/pageSize));
  if(auditPage>=pages&&auditPage>0){auditPage=pages-1;return renderAudit(p)}
  p.innerHTML=`<div class="page">${head('SEGURANÇA','Histórico de atividades','Registros confiáveis, imutáveis e gerados pelo sistema.')}<form class="card audit-filters" id="auditFilters"><label>Buscar<input name="search" value="${esc(auditSearch)}" placeholder="Ação, pessoa ou registro"></label><label>De<input name="from" type="date" value="${esc(auditFrom)}"></label><label>Até<input name="to" type="date" value="${esc(auditTo)}"></label><button class="primary">Filtrar</button><button class="outline" type="button" id="clearAuditFilters">Limpar</button></form><section class="card">${S.audit.map(a=>`<div class="audit-row"><span>${fmt(a.created_at)}</span><b>${esc(a.action)}</b><span>${esc(a.actor_name||'Sistema')} · ${esc(a.entity_type)}</span></div>`).join('')||'<div class="empty">Nenhuma atividade encontrada.</div>'}</section><div class="audit-pagination"><button class="outline" id="auditPrev" ${auditPage===0?'disabled':''}>← Anterior</button><span>Página ${auditPage+1} de ${pages} · ${total} registros</span><button class="outline" id="auditNext" ${auditPage+1>=pages?'disabled':''}>Próxima →</button></div></div>`;
  $('#auditFilters').onsubmit=e=>{e.preventDefault();const f=new FormData(e.target);auditSearch=String(f.get('search')||'').trim();auditFrom=String(f.get('from')||'');auditTo=String(f.get('to')||'');auditPage=0;renderAudit(p)};
  $('#clearAuditFilters').onclick=()=>{auditSearch=auditFrom=auditTo='';auditPage=0;renderAudit(p)};
  $('#auditPrev').onclick=()=>{if(auditPage>0){auditPage--;renderAudit(p)}};
  $('#auditNext').onclick=()=>{if(auditPage+1<pages){auditPage++;renderAudit(p)}};
}
function renderProfile(p){p.innerHTML=`<div class="page">${head('MINHA CONTA','Meu perfil','Visualize seus dados, altere informações pessoais ou sua senha.')}<section class="card profile"><div class="profile-head"><i class="avatar">${initials(S.profile.full_name)}</i><div><h2>${esc(S.profile.full_name)}</h2><p>${S.profile.role==='admin'?'Administradora':'Colaboradora'}</p></div></div><dl><div><dt>Login</dt><dd>${esc(S.profile.username)}</dd></div><div><dt>Harmony ID</dt><dd>${esc(S.profile.harmony_id)}</dd></div><div><dt>Setor</dt><dd>${esc(S.profile.department||'Não informado')}</dd></div><div><dt>Situação</dt><dd>Ativo</dd></div></dl><div class="actions"><button class="primary" id="editOwn">Editar meus dados</button><button class="outline" id="changePass">Alterar senha</button><button class="outline" id="profileLogout">Sair do aplicativo</button></div></section></div>`;$('#profileLogout').onclick=logout;$('#editOwn').onclick=ownProfileModal;$('#changePass').onclick=passwordModal}
