function passwordModal(){$('#modal').innerHTML=`<div class="modal"><form class="modal-box" id="passForm"><div class="modal-head"><h2>Alterar senha</h2><button type="button" data-close>×</button></div><div class="form"><label class="wide">Nova senha<div class="password"><input name="password" type="password" minlength="10" maxlength="72" autocomplete="new-password" required><button type="button" id="seeOwnPass">Ver</button></div></label><label class="wide">Confirmar senha<input name="confirm" type="password" minlength="10" maxlength="72" autocomplete="new-password" required></label><div class="wide password-rules"><b>Sua senha precisa ter:</b><span>10 ou mais caracteres</span><span>Letra maiúscula e minúscula</span><span>Número e símbolo</span></div><div class="form-actions"><button type="button" class="outline" data-close>Cancelar</button><button class="primary">Alterar senha</button></div></div></form></div>`;document.querySelectorAll('[data-close]').forEach(b=>b.onclick=()=>$('#modal').innerHTML='');$('#seeOwnPass').onclick=()=>{let i=$('#passForm [name=password]');i.type=i.type==='password'?'text':'password'};$('#passForm').onsubmit=async e=>{e.preventDefault();let password=e.target.password.value,error=passwordIssue(password);if(!error&&password!==e.target.confirm.value)error='As senhas não coincidem.';if(error)return alert(error);let button=e.submitter;button.disabled=true;try{await changeOwnPassword(password);$('#modal').innerHTML='';toast('Senha alterada com segurança.')}catch(x){alert(x.message);button.disabled=false}}}

async function requestModal(r){try{let items=await rest(`request_items?request_id=eq.${r.id}&select=*`),requester=S.team.find(x=>x.id===r.requested_by)||S.profile,a=S.profile.role==='admin';$('#modal').innerHTML=`<div class="modal"><div class="modal-box large"><div class="modal-head"><div><p class="eyebrow">SOLICITAÇÃO #${String(r.protocol).padStart(4,'0')}</p><h2>${esc(requester.full_name)}</h2></div><button type="button" data-close>×</button></div><div class="request-detail"><section><div class="item-list">${items.map(i=>{let p=S.products.find(x=>x.id===i.product_id);return `<div class="item-editor" data-item="${i.id}"><div><h4>${esc(p?.name||'Produto')}</h4><small>Solicitado: ${i.requested_quantity} ${esc(p?.unit||'')}</small></div><label>Aprovado<input data-approved type="number" min="0" max="${i.requested_quantity}" step=".001" value="${i.approved_quantity??i.requested_quantity}" ${a&&!['delivered','cancelled'].includes(r.status)?'':'disabled'}></label><label>Observação<input data-note value="${esc(i.admin_note||'')}" ${a?'':'disabled'}></label><label class="check"><input data-removed type="checkbox" ${i.removed_by_admin?'checked':''} ${a&&!['delivered','cancelled'].includes(r.status)?'':'disabled'}>Excluir</label></div>`}).join('')}</div>${a&&!['delivered','cancelled'].includes(r.status)?`<label>Observações do ADM<textarea id="adminNotes">${esc(r.admin_notes||'')}</textarea></label><button class="primary full" id="prepareReq">Salvar separação</button>`:''}</section><aside class="timeline"><p><b>Status:</b> ${labels[r.status]}</p><p><b>Criada:</b> ${fmt(r.created_at)}</p><p><b>Modalidade:</b> ${r.fulfillment_method==='delivery'?'Entrega':r.fulfillment_method==='pickup'?'Coleta':'A definir'}</p><p><b>Data:</b> ${fmt(r.scheduled_for)}</p>${r.delivered_by_name?`<p><b>Entregou:</b> ${esc(r.delivered_by_name)}</p><p><b>Recebeu:</b> ${esc(r.received_by_name)}</p>`:''}${a&&r.status==='separating'?`<hr><label>Entrega ou coleta<select id="method"><option value="delivery">Entrega</option><option value="pickup">Coleta</option></select></label><label>Data e horário<input id="schedule" type="datetime-local"></label><button class="primary full" id="scheduleReq">Agendar</button>`:''}${a&&r.status==='scheduled'?`<hr><label>Quem entregou<input id="deliveredBy"></label><label>Quem recebeu<input id="receivedBy"></label><button class="primary full" id="completeReq">Concluir entrega</button>`:''}${a&&!['delivered','cancelled'].includes(r.status)?'<button class="danger full" id="cancelReq">Cancelar solicitação</button>':''}${!a&&r.status==='pending'?'<button class="danger full" id="cancelOwn">Cancelar meu pedido</button>':''}</aside></div></div></div>`;document.querySelectorAll('[data-close]').forEach(b=>b.onclick=()=>$('#modal').innerHTML='');if($('#prepareReq'))$('#prepareReq').onclick=async()=>{let payload=[...document.querySelectorAll('[data-item]')].map(x=>({item_id:x.dataset.item,approved_quantity:+x.querySelector('[data-approved]').value,removed:x.querySelector('[data-removed]').checked,admin_note:x.querySelector('[data-note]').value}));try{await rpc('admin_prepare_request',{p_request_id:r.id,p_items:payload,p_admin_notes:$('#adminNotes').value});await refreshClose('Separação salva.')}catch(e){alert(e.message)}};if($('#scheduleReq'))$('#scheduleReq').onclick=async()=>{try{await rpc('admin_schedule_request',{p_request_id:r.id,p_fulfillment_method:$('#method').value,p_scheduled_for:$('#schedule').value});await refreshClose('Entrega agendada.')}catch(e){alert(e.message)}};if($('#completeReq'))$('#completeReq').onclick=async()=>{try{await rpc('admin_complete_request',{p_request_id:r.id,p_delivered_by_name:$('#deliveredBy').value,p_received_by_name:$('#receivedBy').value});await refreshClose('Entrega concluída e estoque atualizado.')}catch(e){alert(e.message)}};if($('#cancelReq'))$('#cancelReq').onclick=async()=>{let reason=prompt('Motivo do cancelamento:')||'';try{await rpc('admin_cancel_request',{p_request_id:r.id,p_reason:reason});await refreshClose('Solicitação cancelada.')}catch(e){alert(e.message)}};if($('#cancelOwn'))$('#cancelOwn').onclick=async()=>{if(!confirm('Cancelar este pedido?'))return;try{await rpc('cancel_own_pending_request',{p_request_id:r.id});await refreshClose('Pedido cancelado.')}catch(e){alert(e.message)}}}catch(e){alert(e.message)}}
function requestItemVisual(product){
  if(product?.image_path){const url=API+'/storage/v1/object/public/product-images/'+encodedStoragePath(product.image_path);return `<button type="button" class="request-item-photo" data-request-product-photo="${esc(url)}" data-product-name="${esc(product.name)}" aria-label="Ampliar foto de ${esc(product.name)}"><img src="${esc(url)}" alt="${esc(product.name)}"></button>`}
  return `<span class="request-item-photo request-item-photo-fallback" style="background:${esc(product?.color||'#efb6d2')}" aria-hidden="true">✦</span>`;
}
function bindRequestProductPhotos(){document.querySelectorAll('[data-request-product-photo]').forEach(button=>button.onclick=()=>{const viewer=document.createElement('div');viewer.className='photo-lightbox';viewer.innerHTML=`<button type="button" aria-label="Fechar imagem">×</button><img src="${esc(button.dataset.requestProductPhoto)}" alt="${esc(button.dataset.productName)}"><small>${esc(button.dataset.productName)}</small>`;document.querySelector('#modal .modal')?.appendChild(viewer);const close=()=>viewer.remove();viewer.querySelector('button').onclick=close;viewer.onclick=event=>{if(event.target===viewer)close()}})}
function primaryRequestEditButton(request,items){
  if(!S.profile?.is_primary_admin||request.status==='cancelled')return;
  const timeline=document.querySelector('#modal .timeline'),deleteButton=document.querySelector('#deleteReq');if(!timeline)return;
  const button=document.createElement('button');button.type='button';button.id='primaryFullEditReq';button.className='outline full primary-full-edit-trigger';button.innerHTML='✎ Editar solicitação completa';button.onclick=()=>primaryAdminRequestEditModal(request,items);
  timeline.insertBefore(button,deleteButton||null);
}
function primaryAdminRequestEditModal(request,items){
  const editableProducts=S.products.filter(product=>product.usage_scope!=='internal'&&(product.active||items.some(item=>item.product_id===product.id)));
  const rows=items.map(item=>({product_id:item.product_id,requested_quantity:Number(item.requested_quantity),approved_quantity:item.approved_quantity==null?Number(item.requested_quantity):Number(item.approved_quantity),removed:Boolean(item.removed_by_admin),admin_note:item.admin_note||'',original_approved:item.removed_by_admin?0:Number(item.approved_quantity||0)}));
  const delivered=request.status==='delivered',pending=request.status==='pending';
  document.querySelector('#modal').innerHTML=`<div class="modal"><div class="modal-box large primary-request-editor"><div class="modal-head"><div><p class="eyebrow">EDIÇÃO EXCLUSIVA DO ADM PRINCIPAL</p><h2>Solicitação #${String(request.protocol).padStart(4,'0')}</h2><span>${esc(labels[request.status])} · alterações protegidas por auditoria</span></div><button type="button" data-close aria-label="Fechar">×</button></div><section class="primary-request-warning"><b>${delivered?'Correção de uma entrega concluída':'Edição integral da solicitação'}</b><span>${delivered?'O estoque físico e os relatórios serão ajustados pela diferença.':'Produtos e quantidades serão recalculados conforme a fase atual.'}</span></section><div class="primary-product-picker"><label>Buscar produto<input id="primaryProductSearch" type="search" placeholder="Digite o nome do produto"></label><label>Produto<select id="primaryProductSelect"></select></label><button type="button" class="outline" id="primaryAddProduct">＋ Adicionar produto</button></div><div id="primaryRequestItems" class="primary-request-items"></div><div class="primary-request-footer"><div id="primaryRequestImpact" class="primary-request-impact" aria-live="polite"></div><label>Observações do ADM<textarea id="primaryRequestNotes">${esc(request.admin_notes||'')}</textarea></label><label>Motivo desta alteração<input id="primaryRequestReason" minlength="5" placeholder="Ex.: Quantidade conferida após a entrega" required></label><div class="form-actions"><button type="button" class="outline" data-close>Cancelar</button><button type="button" class="primary" id="savePrimaryRequestEdit">Salvar correção</button></div></div></div></div>`;
  const root=$('#primaryRequestItems'),search=$('#primaryProductSearch'),select=$('#primaryProductSelect');
  const product=id=>S.products.find(item=>item.id===id);
  const refreshPicker=()=>{const term=String(search.value||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase(),available=editableProducts.filter(item=>!term||item.name.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().includes(term));select.innerHTML=available.map(item=>`<option value="${item.id}">${esc(item.name)} · ${esc(item.unit)}</option>`).join('')||'<option value="">Nenhum produto encontrado</option>'};
  const renderImpact=()=>{const active=rows.filter(item=>!item.removed),changed=rows.filter(item=>item.removed||Number(item.approved_quantity||0)!==item.original_approved).length;$('#primaryRequestImpact').innerHTML=`<b>${active.length} ${active.length===1?'produto ativo':'produtos ativos'}</b><span>${delivered?changed+' alterações com reflexo automático no estoque e relatórios':'A solicitação permanecerá como '+esc(labels[request.status])}</span>`};
  const renderRows=()=>{root.innerHTML=rows.map((item,index)=>{const p=product(item.product_id),delta=(item.removed?0:Number(item.approved_quantity||0))-item.original_approved,impact=delivered&&delta?`<small class="request-stock-impact ${delta>0?'out':'in'}">${delta>0?'− '+delta+' do estoque':'+ '+Math.abs(delta)+' ao estoque'}</small>`:'';return `<article class="primary-request-item ${item.removed?'removed':''}" data-primary-row="${index}"><div class="request-item-visual">${requestItemVisual(p)}</div><div class="primary-item-copy"><b>${esc(p?.name||'Produto')}</b><small>${esc(p?.unit||'')} · disponível: ${Number(p?.physical_stock||0)-Number(p?.reserved_stock||0)}</small>${impact}</div><label>Solicitado<input data-primary-requested type="number" min="0.001" step="0.001" value="${item.requested_quantity}" ${item.removed?'disabled':''}></label>${pending?'':`<label>${delivered?'Entregue':'Aprovado'}<input data-primary-approved type="number" min="0" step="0.001" value="${item.approved_quantity}" ${item.removed?'disabled':''}></label>`}<label class="primary-item-note">Observação<input data-primary-note value="${esc(item.admin_note)}" ${item.removed?'disabled':''}></label><button type="button" class="${item.removed?'ghost':'danger'}" data-primary-remove>${item.removed?'Restaurar':'Remover'}</button></article>`}).join('')||'<div class="empty">Adicione pelo menos um produto.</div>';bindRequestProductPhotos();root.querySelectorAll('[data-primary-row]').forEach(row=>{const item=rows[Number(row.dataset.primaryRow)],requested=row.querySelector('[data-primary-requested]'),approved=row.querySelector('[data-primary-approved]'),note=row.querySelector('[data-primary-note]');if(requested)requested.oninput=()=>{item.requested_quantity=Number(requested.value);if(approved)approved.max=requested.value;renderImpact()};if(approved)approved.oninput=()=>{item.approved_quantity=Number(approved.value);renderImpact()};if(note)note.oninput=()=>item.admin_note=note.value;row.querySelector('[data-primary-remove]').onclick=()=>{item.removed=!item.removed;renderRows()}});renderImpact()};
  search.oninput=refreshPicker;refreshPicker();
  $('#primaryAddProduct').onclick=()=>{const id=select.value;if(!id)return;const existing=rows.find(item=>item.product_id===id);if(existing){existing.removed=false;renderRows();return}rows.push({product_id:id,requested_quantity:1,approved_quantity:1,removed:false,admin_note:'',original_approved:0});renderRows()};
  document.querySelectorAll('[data-close]').forEach(button=>button.onclick=()=>$('#modal').innerHTML='');
  $('#savePrimaryRequestEdit').onclick=async()=>{const button=$('#savePrimaryRequestEdit'),active=rows.filter(item=>!item.removed),reason=$('#primaryRequestReason').value.trim();if(!active.length)return alert('Mantenha pelo menos um produto na solicitação.');if(reason.length<5)return alert('Informe o motivo da alteração com pelo menos 5 caracteres.');if(active.some(item=>!Number.isFinite(item.requested_quantity)||item.requested_quantity<=0))return alert('Informe quantidades solicitadas maiores que zero.');if(!pending&&active.some(item=>!Number.isFinite(item.approved_quantity)||item.approved_quantity<0||item.approved_quantity>item.requested_quantity))return alert('A quantidade enviada deve ficar entre zero e a quantidade solicitada.');if(delivered&&!confirm('Esta solicitação já foi entregue. Confirmar a correção do estoque e dos relatórios?'))return;button.disabled=true;try{await rpc('primary_admin_update_request',{p_request_id:request.id,p_items:rows.map(item=>({product_id:item.product_id,requested_quantity:item.requested_quantity,approved_quantity:pending?null:item.approved_quantity,removed:item.removed,admin_note:item.admin_note})),p_admin_notes:$('#primaryRequestNotes').value,p_reason:reason});await refreshClose('Solicitação corrigida com estoque e histórico atualizados.')}catch(error){alert(error.message);button.disabled=false}};
  renderRows();
}
