    $('#modal').innerHTML=`<div class="modal"><div class="modal-box large"><div class="modal-head"><div><p class="eyebrow">SOLICITAÇÃO #${String(r.protocol).padStart(4,'0')}</p><h2>${esc(requester.full_name)}</h2></div><div class="modal-head-actions">${a?'<button type="button" class="danger mobile-delete" id="deleteReqMobile">Excluir definitivamente</button>':''}<button type="button" class="modal-close" data-close aria-label="Fechar">×</button></div></div><div class="request-detail"><section>${editor}</section><aside class="timeline"><p><b>Status:</b> ${labels[r.status]}</p><p><b>Criada:</b> ${fmt(r.created_at)}</p><p><b>Modalidade:</b> ${r.fulfillment_method==='delivery'?'Entrega':r.fulfillment_method==='pickup'?'Coleta':'A definir'}</p><p><b>Data:</b> ${fmt(r.scheduled_for)}</p>${r.delivered_by_name?`<p><b>Entregou:</b> ${esc(r.delivered_by_name)}</p><p><b>Recebeu:</b> ${esc(r.received_by_name)}</p>`:''}${a&&r.status==='separating'?`<hr><label>Entrega ou coleta<select id="method"><option value="delivery">Entrega</option><option value="pickup">Coleta</option></select></label><label>Data e horário<input id="schedule" type="datetime-local"></label><button class="primary full" id="scheduleReq">Agendar para depois</button><div class="request-complete-now"><b>O material já foi entregue?</b><small>Confirme agora sem precisar criar um agendamento.</small><label>Quem entregou<input id="deliveredByNow" autocomplete="name"></label><label>Quem recebeu<input id="receivedByNow" autocomplete="name"></label><button class="primary full" id="completeReqNow">✓ Concluir entrega agora</button></div>`:''}${a&&r.status==='scheduled'?`<hr><label>Quem entregou<input id="deliveredBy"></label><label>Quem recebeu<input id="receivedBy"></label><button class="primary full" id="completeReq">Concluir entrega</button>`:''}${a?'<button class="danger full" id="deleteReq">Excluir definitivamente</button>':''}${!a&&r.status==='pending'?'<button class="danger full" id="cancelOwn">Cancelar meu pedido</button>':''}</aside></div></div></div>`;
    document.querySelectorAll('[data-close]').forEach(b=>b.onclick=()=>$('#modal').innerHTML='');bindRequestProductPhotos();primaryRequestEditButton(r,items);
    if($('#saveOwnRequest'))$('#saveOwnRequest').onclick=async()=>{let button=$('#saveOwnRequest'),payload=[...document.querySelectorAll('[data-own-product]')].map(x=>({product_id:x.dataset.ownProduct,requested_quantity:+x.value})).filter(x=>x.requested_quantity>0);if(!payload.length)return alert('Escolha ao menos um produto.');button.disabled=true;try{await rpc('update_own_pending_request',{p_request_id:r.id,p_notes:$('#ownRequestNotes').value,p_items:payload});await refreshClose('Solicitação atualizada.')}catch(e){alert(e.message);button.disabled=false}};
