    if($('#completeReq'))$('#completeReq').onclick=async()=>{let button=$('#completeReq'),delivered=$('#deliveredBy').value.trim(),received=$('#receivedBy').value.trim();if(!delivered||!received)return alert('Informe quem entregou e quem recebeu.');button.disabled=true;try{await rpc('admin_complete_request',{p_request_id:r.id,p_delivered_by_name:delivered,p_received_by_name:received});await refreshClose('Entrega concluída e estoque atualizado.')}catch(e){alert(e.message);button.disabled=false}};
