async function replaceAvatar(element,profile){
  if(!element||!profile?.avatar_path||element.dataset.avatarPath===profile.avatar_path||element.dataset.avatarLoading===profile.avatar_path)return;
  const path=profile.avatar_path;element.dataset.avatarLoading=path;
  try{
    const url=await privateProfilePhotoUrl(profile);
    if(!element.isConnected||element.dataset.avatarLoading!==path)return;
    const image=document.createElement('img');
    image.className='avatar avatar-photo';
    image.src=url;
    image.alt='Foto de '+profile.full_name;
    image.dataset.avatarPath=path;
    element.replaceWith(image);
  }catch{delete element.dataset.avatarLoading}
}

function enhanceProfilePhotos(){
  if(!S.profile)return;
  replaceAvatar(document.querySelector('.account .avatar'),S.profile);
  replaceAvatar(document.querySelector('.profile-head .avatar'),S.profile);
  document.querySelectorAll('.person').forEach(card=>{
    const name=card.querySelector('h3')?.textContent;
    replaceAvatar(card.querySelector('.avatar'),S.team.find(person=>person.full_name===name));
  });
  const actions=document.querySelector('.profile .actions');
  if(actions&&!document.querySelector('#changePhoto')){
    const button=document.createElement('button');
    button.type='button';
    button.className='primary';
    button.id='changePhoto';
    button.textContent=S.profile.avatar_path?'Alterar foto':'Adicionar foto';
    button.onclick=profilePhotoModal;
    actions.prepend(button);
  }
}

async function deleteProfilePhoto(path){
  if(!path)return;
  const response=await storageFetch('/storage/v1/object/profile-images/'+encodedStoragePath(path),{method:'DELETE'});
  if(!response.ok)throw Error('Não foi possível remover a foto anterior.');
  releaseProfilePhoto(path);
}

function profilePhotoModal(){
  $('#modal').innerHTML=`<div class="modal"><form class="modal-box" id="profilePhotoForm"><div class="modal-head"><div><p class="eyebrow">FOTO DE PERFIL</p><h2>${S.profile.avatar_path?'Alterar foto':'Adicionar foto'}</h2></div><button type="button" data-close>×</button></div><div class="profile-photo-editor"><i class="avatar" id="profilePhotoPreview">${initials(S.profile.full_name)}</i><p>Escolha uma imagem JPG, PNG ou WebP com até 2 MB.</p><label>Nova foto<input name="photo" type="file" accept="image/jpeg,image/png,image/webp"></label><div class="form-actions">${S.profile.avatar_path?'<button type="button" class="danger" id="removeProfilePhoto">Remover foto</button>':''}<button type="button" class="outline" data-close>Cancelar</button><button class="primary">Salvar foto</button></div></div></form></div>`;
  if(S.profile.avatar_path)replaceAvatar($('#profilePhotoPreview'),S.profile);
  document.querySelectorAll('[data-close]').forEach(button=>button.onclick=()=>$('#modal').innerHTML='');
  if($('#removeProfilePhoto'))$('#removeProfilePhoto').onclick=async()=>{
    if(!confirm('Remover sua foto de perfil?'))return;
    try{const old=S.profile.avatar_path;await rpc('update_own_avatar',{p_avatar_path:null});await deleteProfilePhoto(old);$('#modal').innerHTML='';await loadAccount();renderApp();toast('Foto removida.')}catch(error){alert(error.message)}
  };
  $('#profilePhotoForm').onsubmit=async event=>{
    event.preventDefault();
    const button=event.submitter,file=new FormData(event.target).get('photo');
    if(!file?.size)return alert('Escolha uma foto para enviar.');
    if(file.size>2097152)return alert('A foto deve ter no máximo 2 MB.');
    if(!['image/jpeg','image/png','image/webp'].includes(file.type))return alert('Use uma imagem JPG, PNG ou WebP.');
    button.disabled=true;
    const old=S.profile.avatar_path,path=S.profile.id+'/'+crypto.randomUUID()+'-'+file.name.replace(/[^a-zA-Z0-9._-]/g,'-');
    try{
      const upload=await storageFetch('/storage/v1/object/profile-images/'+encodedStoragePath(path),{method:'POST',headers:{'Content-Type':file.type},body:file});
      await json(upload);
      await rpc('update_own_avatar',{p_avatar_path:path});
      if(old)await deleteProfilePhoto(old).catch(()=>{});
      $('#modal').innerHTML='';await loadAccount();renderApp();toast('Foto de perfil atualizada.');
    }catch(error){alert(error.message);button.disabled=false}
  };
}

new MutationObserver(enhanceProfilePhotos).observe($('#app'),{childList:true,subtree:true});

const renderNewBase=renderNew;
renderNew=function(p){
  renderNewBase(p);
  const button=$('#sendReq');
  if(!button)return;
  button.onclick=async()=>{
    const items=S.products.filter(product=>(S.cart[product.id]||0)>0).map(product=>({product_id:product.id,requested_quantity:S.cart[product.id]}));
    if(!items.length)return alert('Escolha ao menos um produto.');
    button.disabled=true;
    try{
      await rpc('create_own_request',{p_notes:$('#reqNotes').value,p_items:items});
      S.cart={};await loadData();S.view='requests';renderApp();toast('Solicitação enviada com sucesso.');
    }catch(error){alert(error.message);button.disabled=false}
  };
};

async function refreshClose(message){$('#modal').innerHTML='';await loadData();renderApp();toast(message)}

$('#app').innerHTML='<div class="loading"><img src="logo.jpg" alt="Harmony Store"><span>Preparando ambiente seguro…</span></div>';restore().then(ok=>ok?renderApp():renderLogin());
